const input = $json.body ?? $json;
const clean = (value) => typeof value === 'string' ? value.trim() : '';
const lead = { name: clean(input.name), email: clean(input.email).toLowerCase(), company: clean(input.company), teamSize: Number(input.teamSize) || 0, monthlyLeads: Number(input.monthlyLeads) || 0, pain: clean(input.pain) };
const errors = [];
if (!lead.name) errors.push('name is required');
if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(lead.email)) errors.push('a valid email is required');
if (errors.length) return [{ json: { ok: false, route: 'needs-correction', errors } }];
let score = 0;
const reasons = [];
if (lead.company) { score += 15; reasons.push('company identified'); }
if (lead.teamSize >= 2 && lead.teamSize <= 30) { score += 20; reasons.push('team matches initial customer profile'); }
if (lead.monthlyLeads >= 50) { score += 25; reasons.push('lead volume makes response automation valuable'); }
if (/manual|copy|spreadsheet|delay|wait|miss|duplicate|fail|break/i.test(lead.pain)) { score += 30; reasons.push('concrete automation pain detected'); }
if (lead.pain.length >= 40) { score += 10; reasons.push('problem includes useful detail'); }
return [{ json: { ok: true, lead, score, route: score >= 60 ? 'priority-review' : 'standard-review', reasons } }];
